@page "/"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext>? DbFactoryNullable
@inject IServiceProvider ServiceProvider

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="text-white">Manage →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="/appointments" class="text-white">View →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidInvoices</p>
                <a href="/billing" class="text-white">View →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="/patients" class="text-white">Manage →</a>
            </div>
        </div>
    </div>
</div>

<h3 class="mt-4">Upcoming Appointments</h3>
@if (upcomingAppointments?.Any() == true)
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th></tr>
        </thead>
        <tbody>
            @foreach (var apt in upcomingAppointments)
            {
                <tr>
                    <td>@apt.StartTime.ToString("g")</td>
                    <td>@apt.Pet.Name</td>
                    <td>@apt.Pet.Owner.FullName</td>
                    <td>@apt.Reason</td>
                    <td>@apt.Veterinarian</td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No upcoming appointments.</p>
}

@code {
    private int petCount, todayAppointments, unpaidInvoices, ownerCount;
    private List<VetClinic.Data.Appointment>? upcomingAppointments;

    protected override async Task OnInitializedAsync()
    {
        using var db = CreateDbContext();
        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayAppointments = await db.Appointments
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .CountAsync();
        unpaidInvoices = await db.Invoices
            .Include(i => i.LineItems).Include(i => i.Payments)
            .Where(i => i.LineItems.Sum(li => li.Amount) > i.Payments.Sum(p => p.Amount))
            .CountAsync();
        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(10)
            .ToListAsync();
    }

    private VetClinic.Data.ApplicationDbContext CreateDbContext()
    {
        if (DbFactoryNullable != null)
            return DbFactoryNullable.CreateDbContext();
        return ServiceProvider.GetRequiredService<VetClinic.Data.ApplicationDbContext>();
    }
}

@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IServiceProvider ServiceProvider

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                        <ValidationMessage For="() => editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="editingPet.Species" />
                        <ValidationMessage For="() => editingPet.Species" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-control" @bind-Value="editingPet.OwnerId">
                            <option value="0">-- Select --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-3">
                        <label class="form-label">Microchip ID</label>
                        <InputText class="form-control" @bind-Value="editingPet.MicrochipId" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="() => showPetForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (selectedPet != null)
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between">
            <span>Medical History - @selectedPet.Name (@selectedPet.Species@(selectedPet.Breed != null ? $" / {selectedPet.Breed}" : ""))</span>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedPet = null">Close</button>
        </div>
        <div class="card-body">
            <h6>Treatment Notes</h6>
            @if (selectedPet.TreatmentNotes?.Any() == true)
            {
                @foreach (var note in selectedPet.TreatmentNotes.OrderByDescending(n => n.Date))
                {
                    <div class="border-start border-3 border-primary ps-3 mb-2">
                        <strong>@note.Date.ToString("d") - @note.Title</strong> <small class="text-muted">(@note.Veterinarian)</small>
                        <p class="mb-0">@note.Description</p>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No treatment notes yet.</p>
            }

            <hr />
            <h6>Add Treatment Note</h6>
            <EditForm Model="newNote" OnValidSubmit="SaveNote">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <InputText class="form-control" placeholder="Title" @bind-Value="newNote.Title" />
                        <ValidationMessage For="() => newNote.Title" />
                    </div>
                    <div class="col-md-3">
                        <InputText class="form-control" placeholder="Veterinarian" @bind-Value="newNote.Veterinarian" />
                    </div>
                    <div class="col-md-4">
                        <InputTextArea class="form-control" placeholder="Description" @bind-Value="newNote.Description" />
                        <ValidationMessage For="() => newNote.Description" />
                    </div>
                    <div class="col-md-2">
                        <button type="submit" class="btn btn-success">Add Note</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-info" @onclick="() => SelectPet(pet.Id)">History</button>
                    <button class="btn btn-sm btn-warning" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Pet? selectedPet;
    private TreatmentNote newNote = new();

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = CreateDbContext();
        pets = await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new Owner(); showOwnerForm = true; }
    private void ShowAddPet() { editingPet = new Pet(); showPetForm = true; }
    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, WeightKg = pet.WeightKg, MicrochipId = pet.MicrochipId, OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task SaveOwner()
    {
        using var db = CreateDbContext();
        if (editingOwner.Id == 0)
            db.Owners.Add(editingOwner);
        else
            db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        using var db = CreateDbContext();
        if (editingPet.Id == 0)
            db.Pets.Add(editingPet);
        else
            db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task SelectPet(int petId)
    {
        using var db = CreateDbContext();
        selectedPet = await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes).FirstOrDefaultAsync(p => p.Id == petId);
        newNote = new TreatmentNote { PetId = petId };
    }

    private async Task SaveNote()
    {
        using var db = CreateDbContext();
        newNote.Date = DateTime.Now;
        db.TreatmentNotes.Add(newNote);
        await db.SaveChangesAsync();
        await SelectPet(newNote.PetId);
    }

    private ApplicationDbContext CreateDbContext() => ServiceProvider.GetRequiredService<ApplicationDbContext>();
}

@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IServiceProvider ServiceProvider

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="viewDate" @bind:event="onchange" @bind:after="LoadData" />
    </div>
    <div class="col-auto d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-1">
                        <label class="form-label">Duration</label>
                        <InputSelect class="form-control" @bind-Value="durationMinutes">
                            <option value="15">15m</option>
                            <option value="30">30m</option>
                            <option value="45">45m</option>
                            <option value="60">60m</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        <ValidationMessage For="() => editingAppointment.Reason" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (!string.IsNullOrEmpty(conflictMessage))
{
    <div class="alert alert-danger">@conflictMessage</div>
}

<h4>Schedule for @viewDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <div class="border rounded p-2" style="min-height:400px;">
            @for (int hour = 8; hour < 18; hour++)
            {
                var h = hour;
                var slotTime = viewDate.Date.AddHours(h);
                var slotAppointments = appointments.Where(a => a.StartTime.Hour == h).ToList();
                var isAvailable = !slotAppointments.Any();

                <div class="d-flex border-bottom py-1">
                    <div class="fw-bold me-3" style="width:60px;">@slotTime.ToString("HH:mm")</div>
                    <div class="flex-grow-1">
                        @if (slotAppointments.Any())
                        {
                            @foreach (var apt in slotAppointments)
                            {
                                <span class="badge @(apt.Status == AppointmentStatus.Cancelled ? "bg-secondary" : "bg-primary") me-1">
                                    @apt.Pet.Name - @apt.Reason (@apt.StartTime.ToString("HH:mm")-@apt.EndTime.ToString("HH:mm"))
                                </span>
                                @if (apt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-warning" @onclick="() => EditAppointment(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt.Id)">Cancel</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => CompleteAppointment(apt.Id)">Complete</button>
                                }
                            }
                        }
                        else
                        {
                            <span class="text-success">Available</span>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
    <div class="col-md-4">
        <h5>All Scheduled</h5>
        <ul class="list-group">
            @foreach (var apt in appointments.Where(a => a.Status == AppointmentStatus.Scheduled).OrderBy(a => a.StartTime))
            {
                <li class="list-group-item">
                    <strong>@apt.StartTime.ToString("HH:mm")</strong> @apt.Pet.Name - @apt.Reason
                    <br /><small class="text-muted">Vet: @apt.Veterinarian</small>
                </li>
            }
        </ul>
    </div>
</div>

@code {
    private DateTime viewDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private int durationMinutes = 30;
    private string? conflictMessage;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = CreateDbContext();
        var dayStart = viewDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        conflictMessage = null;
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment { StartTime = viewDate.Date.AddHours(9) };
        durationMinutes = 30;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = new Appointment
        {
            Id = apt.Id, PetId = apt.PetId, StartTime = apt.StartTime,
            EndTime = apt.EndTime, Reason = apt.Reason, Veterinarian = apt.Veterinarian, Notes = apt.Notes
        };
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);

        using var db = CreateDbContext();
        // Check for conflicts
        var hasConflict = await db.Appointments
            .Where(a => a.Id != editingAppointment.Id && a.Status == AppointmentStatus.Scheduled)
            .Where(a => a.Veterinarian == editingAppointment.Veterinarian && a.Veterinarian != null)
            .Where(a => a.StartTime < editingAppointment.EndTime && a.EndTime > editingAppointment.StartTime)
            .AnyAsync();

        if (hasConflict)
        {
            conflictMessage = "Time conflict: this veterinarian already has an appointment in that slot.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        await LoadData();
    }

    private async Task CancelAppointment(int id)
    {
        using var db = CreateDbContext();
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private async Task CompleteAppointment(int id)
    {
        using var db = CreateDbContext();
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private ApplicationDbContext CreateDbContext() => ServiceProvider.GetRequiredService<ApplicationDbContext>();
}

@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IServiceProvider ServiceProvider

<PageTitle>Billing</PageTitle>

<h1>Billing & Payments</h1>

<div class="row mb-3">
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>
    <div class="col">
        <select class="form-select" @bind="filterStatus">
            <option value="all">All Invoices</option>
            <option value="unpaid">Unpaid Only</option>
            <option value="paid">Paid Only</option>
        </select>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-header">New Invoice</div>
        <div class="card-body">
            <div class="row mb-2">
                <div class="col-md-3">
                    <label class="form-label">Owner</label>
                    <select class="form-control" @bind="newInvoiceOwnerId" @bind:after="OnOwnerSelected">
                        <option value="0">-- Select Owner --</option>
                        @foreach (var o in owners)
                        {
                            <option value="@o.Id">@o.FullName</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Pet (optional)</label>
                    <select class="form-control" @bind="newInvoicePetId">
                        <option value="0">-- All pets --</option>
                        @foreach (var p in ownerPets)
                        {
                            <option value="@p.Id">@p.Name</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="newInvoiceDueDate" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newInvoiceDescription" />
                </div>
            </div>

            <h6>Line Items</h6>
            @for (int i = 0; i < lineItems.Count; i++)
            {
                var idx = i;
                <div class="row mb-1">
                    <div class="col-md-6">
                        <input type="text" class="form-control" placeholder="Description" @bind="lineItems[idx].Description" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" class="form-control" step="0.01" placeholder="Amount" @bind="lineItems[idx].Amount" />
                    </div>
                    <div class="col-md-2">
                        <button class="btn btn-sm btn-danger" @onclick="() => lineItems.RemoveAt(idx)">Remove</button>
                    </div>
                </div>
            }
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => lineItems.Add(new InvoiceLineItem())">+ Add Line</button>
            <div class="mt-2">
                <strong>Total: @lineItems.Sum(l => l.Amount).ToString("C")</strong>
            </div>
            <hr />
            <button class="btn btn-primary" @onclick="SaveInvoice">Create Invoice</button>
            <button class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPaymentForm)
{
    <div class="card mb-3">
        <div class="card-header">Record Payment for Invoice #@paymentInvoiceId</div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-3">
                    <label class="form-label">Amount</label>
                    <input type="number" class="form-control" step="0.01" @bind="newPayment.Amount" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Method</label>
                    <InputSelect class="form-control" @bind-Value="newPayment.Method">
                        @foreach (var m in Enum.GetValues<PaymentMethod>())
                        {
                            <option value="@m">@m</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Reference</label>
                    <input type="text" class="form-control" @bind="newPayment.Reference" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button class="btn btn-success me-2" @onclick="SavePayment">Record Payment</button>
                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Date</th><th>Owner</th><th>Pet</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in FilteredInvoices)
        {
            <tr class="@(inv.IsPaid ? "table-success" : "")">
                <td>@inv.Id</td>
                <td>@inv.CreatedDate.ToString("d")</td>
                <td>@inv.Owner.FullName</td>
                <td>@(inv.Pet?.Name ?? "-")</td>
                <td>@inv.Description</td>
                <td>@inv.Total.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td>@inv.Balance.ToString("C")</td>
                <td>
                    @if (!inv.IsPaid)
                    {
                        <button class="btn btn-sm btn-success" @onclick="() => ShowPayment(inv.Id, inv.Balance)">Pay</button>
                    }
                    <button class="btn btn-sm btn-info" @onclick="() => ViewPaymentHistory(inv.Id)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showPaymentHistory)
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between">
            <span>Payment History - Invoice #@paymentHistoryInvoiceId</span>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => showPaymentHistory = false">Close</button>
        </div>
        <div class="card-body">
            @if (paymentHistory.Any())
            {
                <table class="table table-sm">
                    <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                    <tbody>
                        @foreach (var p in paymentHistory)
                        {
                            <tr>
                                <td>@p.Date.ToString("g")</td>
                                <td>@p.Amount.ToString("C")</td>
                                <td>@p.Method</td>
                                <td>@p.Reference</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No payments recorded.</p>
            }
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private List<Pet> ownerPets = [];
    private string filterStatus = "all";

    private bool showInvoiceForm, showPaymentForm, showPaymentHistory;
    private int newInvoiceOwnerId, newInvoicePetId;
    private DateTime? newInvoiceDueDate;
    private string? newInvoiceDescription;
    private List<InvoiceLineItem> lineItems = [new()];

    private Payment newPayment = new();
    private int paymentInvoiceId;

    private int paymentHistoryInvoiceId;
    private List<Payment> paymentHistory = [];

    private IEnumerable<Invoice> FilteredInvoices => filterStatus switch
    {
        "unpaid" => invoices.Where(i => !i.IsPaid),
        "paid" => invoices.Where(i => i.IsPaid),
        _ => invoices
    };

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = CreateDbContext();
        invoices = await db.Invoices
            .Include(i => i.Owner).Include(i => i.Pet)
            .Include(i => i.LineItems).Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoiceOwnerId = 0;
        newInvoicePetId = 0;
        newInvoiceDueDate = DateTime.Today.AddDays(30);
        newInvoiceDescription = "";
        lineItems = [new InvoiceLineItem()];
        ownerPets = [];
        showInvoiceForm = true;
    }

    private async Task OnOwnerSelected()
    {
        if (newInvoiceOwnerId > 0)
        {
            using var db = CreateDbContext();
            ownerPets = await db.Pets.Where(p => p.OwnerId == newInvoiceOwnerId).ToListAsync();
        }
        else
        {
            ownerPets = [];
        }
    }

    private async Task SaveInvoice()
    {
        if (newInvoiceOwnerId == 0 || !lineItems.Any(l => l.Amount > 0)) return;

        using var db = CreateDbContext();
        var invoice = new Invoice
        {
            OwnerId = newInvoiceOwnerId,
            PetId = newInvoicePetId > 0 ? newInvoicePetId : null,
            CreatedDate = DateTime.Now,
            DueDate = newInvoiceDueDate,
            Description = newInvoiceDescription,
            LineItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description) || l.Amount > 0).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPayment(int invoiceId, decimal balance)
    {
        paymentInvoiceId = invoiceId;
        newPayment = new Payment { InvoiceId = invoiceId, Amount = balance, Date = DateTime.Now };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        using var db = CreateDbContext();
        newPayment.Date = DateTime.Now;
        newPayment.InvoiceId = paymentInvoiceId;
        db.Payments.Add(newPayment);
        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private async Task ViewPaymentHistory(int invoiceId)
    {
        using var db = CreateDbContext();
        paymentHistoryInvoiceId = invoiceId;
        paymentHistory = await db.Payments.Where(p => p.InvoiceId == invoiceId).OrderByDescending(p => p.Date).ToListAsync();
        showPaymentHistory = true;
    }

    private ApplicationDbContext CreateDbContext() => ServiceProvider.GetRequiredService<ApplicationDbContext>();
}

@page "/"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext>? DbFactoryNullable
@inject IServiceProvider ServiceProvider

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="text-white">Manage →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="/appointments" class="text-white">View →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidInvoices</p>
                <a href="/billing" class="text-white">View →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="/patients" class="text-white">Manage →</a>
            </div>
        </div>
    </div>
</div>

<h3 class="mt-4">Upcoming Appointments</h3>
@if (upcomingAppointments?.Any() == true)
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th></tr>
        </thead>
        <tbody>
            @foreach (var apt in upcomingAppointments)
            {
                <tr>
                    <td>@apt.StartTime.ToString("g")</td>
                    <td>@apt.Pet.Name</td>
                    <td>@apt.Pet.Owner.FullName</td>
                    <td>@apt.Reason</td>
                    <td>@apt.Veterinarian</td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No upcoming appointments.</p>
}

@code {
    private int petCount, todayAppointments, unpaidInvoices, ownerCount;
    private List<VetClinic.Data.Appointment>? upcomingAppointments;

    protected override async Task OnInitializedAsync()
    {
        using var db = CreateDbContext();
        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayAppointments = await db.Appointments
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .CountAsync();
        unpaidInvoices = await db.Invoices
            .Include(i => i.LineItems).Include(i => i.Payments)
            .Where(i => i.LineItems.Sum(li => li.Amount) > i.Payments.Sum(p => p.Amount))
            .CountAsync();
        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(10)
            .ToListAsync();
    }

    private VetClinic.Data.ApplicationDbContext CreateDbContext()
    {
        if (DbFactoryNullable != null)
            return DbFactoryNullable.CreateDbContext();
        return ServiceProvider.GetRequiredService<VetClinic.Data.ApplicationDbContext>();
    }
}

@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IServiceProvider ServiceProvider

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                        <ValidationMessage For="() => editingPet.Name" />
                    </div>
