@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IServiceProvider ServiceProvider

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="viewDate" @bind:event="onchange" @bind:after="LoadData" />
    </div>
    <div class="col-auto d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-1">
                        <label class="form-label">Duration</label>
                        <InputSelect class="form-control" @bind-Value="durationMinutes">
                            <option value="15">15m</option>
                            <option value="30">30m</option>
                            <option value="45">45m</option>
                            <option value="60">60m</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        <ValidationMessage For="() => editingAppointment.Reason" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (!string.IsNullOrEmpty(conflictMessage))
{
    <div class="alert alert-danger">@conflictMessage</div>
}

<h4>Schedule for @viewDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <div class="border rounded p-2" style="min-height:400px;">
            @for (int hour = 8; hour < 18; hour++)
            {
                var h = hour;
                var slotTime = viewDate.Date.AddHours(h);
                var slotAppointments = appointments.Where(a => a.StartTime.Hour == h).ToList();
                var isAvailable = !slotAppointments.Any();

                <div class="d-flex border-bottom py-1">
                    <div class="fw-bold me-3" style="width:60px;">@slotTime.ToString("HH:mm")</div>
                    <div class="flex-grow-1">
                        @if (slotAppointments.Any())
                        {
                            @foreach (var apt in slotAppointments)
                            {
                                <span class="badge @(apt.Status == AppointmentStatus.Cancelled ? "bg-secondary" : "bg-primary") me-1">
                                    @apt.Pet.Name - @apt.Reason (@apt.StartTime.ToString("HH:mm")-@apt.EndTime.ToString("HH:mm"))
                                </span>
                                @if (apt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-warning" @onclick="() => EditAppointment(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt.Id)">Cancel</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => CompleteAppointment(apt.Id)">Complete</button>
                                }
                            }
                        }
                        else
                        {
                            <span class="text-success">Available</span>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
    <div class="col-md-4">
        <h5>All Scheduled</h5>
        <ul class="list-group">
            @foreach (var apt in appointments.Where(a => a.Status == AppointmentStatus.Scheduled).OrderBy(a => a.StartTime))
            {
                <li class="list-group-item">
                    <strong>@apt.StartTime.ToString("HH:mm")</strong> @apt.Pet.Name - @apt.Reason
                    <br /><small class="text-muted">Vet: @apt.Veterinarian</small>
                </li>
            }
        </ul>
    </div>
</div>

@code {
    private DateTime viewDate = DateTime.Today;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private int durationMinutes = 30;
    private string? conflictMessage;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = CreateDbContext();
        var dayStart = viewDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        conflictMessage = null;
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment { StartTime = viewDate.Date.AddHours(9) };
        durationMinutes = 30;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = new Appointment
        {
            Id = apt.Id, PetId = apt.PetId, StartTime = apt.StartTime,
            EndTime = apt.EndTime, Reason = apt.Reason, Veterinarian = apt.Veterinarian, Notes = apt.Notes
        };
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);

        using var db = CreateDbContext();
        // Check for conflicts
        var hasConflict = await db.Appointments
            .Where(a => a.Id != editingAppointment.Id && a.Status == AppointmentStatus.Scheduled)
            .Where(a => a.Veterinarian == editingAppointment.Veterinarian && a.Veterinarian != null)
            .Where(a => a.StartTime < editingAppointment.EndTime && a.EndTime > editingAppointment.StartTime)
            .AnyAsync();

        if (hasConflict)
        {
            conflictMessage = "Time conflict: this veterinarian already has an appointment in that slot.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        await LoadData();
    }

    private async Task CancelAppointment(int id)
    {
        using var db = CreateDbContext();
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private async Task CompleteAppointment(int id)
    {
        using var db = CreateDbContext();
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private ApplicationDbContext CreateDbContext() => ServiceProvider.GetRequiredService<ApplicationDbContext>();
}
