                </div>
                <div class="col-md-3">
                    <label class="form-label">Reference</label>
                    <input type="text" class="form-control" @bind="newPayment.Reference" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button class="btn btn-success me-2" @onclick="SavePayment">Record Payment</button>
                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Date</th><th>Owner</th><th>Pet</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in FilteredInvoices)
        {
            <tr class="@(inv.IsPaid ? "table-success" : "")">
                <td>@inv.Id</td>
                <td>@inv.CreatedDate.ToString("d")</td>
                <td>@inv.Owner.FullName</td>
                <td>@(inv.Pet?.Name ?? "-")</td>
                <td>@inv.Description</td>
                <td>@inv.Total.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td>@inv.Balance.ToString("C")</td>
                <td>
                    @if (!inv.IsPaid)
                    {
                        <button class="btn btn-sm btn-success" @onclick="() => ShowPayment(inv.Id, inv.Balance)">Pay</button>
                    }
                    <button class="btn btn-sm btn-info" @onclick="() => ViewPaymentHistory(inv.Id)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showPaymentHistory)
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between">
            <span>Payment History - Invoice #@paymentHistoryInvoiceId</span>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => showPaymentHistory = false">Close</button>
        </div>
        <div class="card-body">
            @if (paymentHistory.Any())
            {
                <table class="table table-sm">
                    <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                    <tbody>
                        @foreach (var p in paymentHistory)
                        {
                            <tr>
                                <td>@p.Date.ToString("g")</td>
                                <td>@p.Amount.ToString("C")</td>
                                <td>@p.Method</td>
                                <td>@p.Reference</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No payments recorded.</p>
            }
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private List<Pet> ownerPets = [];
    private string filterStatus = "all";

    private bool showInvoiceForm, showPaymentForm, showPaymentHistory;
    private int newInvoiceOwnerId, newInvoicePetId;
    private DateTime? newInvoiceDueDate;
    private string? newInvoiceDescription;
    private List<InvoiceLineItem> lineItems = [new()];

    private Payment newPayment = new();
    private int paymentInvoiceId;

    private int paymentHistoryInvoiceId;
    private List<Payment> paymentHistory = [];

    private IEnumerable<Invoice> FilteredInvoices => filterStatus switch
    {
        "unpaid" => invoices.Where(i => !i.IsPaid),
        "paid" => invoices.Where(i => i.IsPaid),
        _ => invoices
    };

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = CreateDbContext();
        invoices = await db.Invoices
            .Include(i => i.Owner).Include(i => i.Pet)
            .Include(i => i.LineItems).Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoiceOwnerId = 0;
        newInvoicePetId = 0;
        newInvoiceDueDate = DateTime.Today.AddDays(30);
        newInvoiceDescription = "";
        lineItems = [new InvoiceLineItem()];
        ownerPets = [];
        showInvoiceForm = true;
    }

    private async Task OnOwnerSelected()
    {
        if (newInvoiceOwnerId > 0)
        {
            using var db = CreateDbContext();
            ownerPets = await db.Pets.Where(p => p.OwnerId == newInvoiceOwnerId).ToListAsync();
        }
        else
        {
            ownerPets = [];
        }
    }

    private async Task SaveInvoice()
    {
        if (newInvoiceOwnerId == 0 || !lineItems.Any(l => l.Amount > 0)) return;

        using var db = CreateDbContext();
        var invoice = new Invoice
        {
            OwnerId = newInvoiceOwnerId,
            PetId = newInvoicePetId > 0 ? newInvoicePetId : null,
            CreatedDate = DateTime.Now,
            DueDate = newInvoiceDueDate,
            Description = newInvoiceDescription,
            LineItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description) || l.Amount > 0).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPayment(int invoiceId, decimal balance)
    {
        paymentInvoiceId = invoiceId;
        newPayment = new Payment { InvoiceId = invoiceId, Amount = balance, Date = DateTime.Now };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        using var db = CreateDbContext();
        newPayment.Date = DateTime.Now;
        newPayment.InvoiceId = paymentInvoiceId;
        db.Payments.Add(newPayment);
        await db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private async Task ViewPaymentHistory(int invoiceId)
    {
        using var db = CreateDbContext();
        paymentHistoryInvoiceId = invoiceId;
        paymentHistory = await db.Payments.Where(p => p.InvoiceId == invoiceId).OrderByDescending(p => p.Date).ToListAsync();
        showPaymentHistory = true;
    }

    private ApplicationDbContext CreateDbContext() => ServiceProvider.GetRequiredService<ApplicationDbContext>();
}
